    html = '<style>\n:root{--bg:#f5f0e8;--surface:#ffffff;--surface2:#f9f6f0;--border:#e0d8cc;--navy:#1a2340;--amber:#e8941a;--teal:#0a8a72;--red:#c0392b;--purple:#6c3fc5;--blue:#1a5fa8;--text:#1e1e1e;--muted:#6b6560;}\n*{box-sizing:border-box;margin:0;padding:0;}\nbody{font-family:\'Segoe UI\',Arial,sans-serif;background:var(--bg);color:var(--text);font-size:15px;line-height:1.6;}\n#MainMenu,footer,header{visibility:hidden;}\n.block-container{padding:0!important;max-width:100%!important;}\n.guide-tabs{display:flex;background:var(--navy);padding:0 32px;position:sticky;top:0;z-index:100;border-bottom:3px solid var(--amber);}\n.guide-tab{padding:16px 28px;font-size:.88rem;font-weight:700;letter-spacing:.06em;text-transform:uppercase;color:rgba(255,255,255,0.5);cursor:pointer;border-bottom:3px solid transparent;margin-bottom:-3px;transition:all .2s;user-select:none;}\n.guide-tab:hover{color:rgba(255,255,255,0.85);}\n.guide-tab.active{color:var(--amber);border-bottom:3px solid var(--amber);}\n.tab-panel{display:none;}\n.tab-panel.active{display:block;}\n.guide-wrap{background:var(--bg);color:var(--text);font-family:\'Segoe UI\',Arial,sans-serif;font-size:15px;line-height:1.6;min-height:100vh;}\n.guide-page{max-width:860px;margin:0 auto;padding:0 32px 64px;}\n.cover{background:var(--navy);color:#fff;padding:52px 48px 44px;position:relative;overflow:hidden;}\n.cover-header{display:flex;align-items:center;gap:14px;margin-bottom:20px;}\n.cover-header img{width:48px;height:48px;border-radius:10px;flex-shrink:0;}\n.cover-logo{font-size:2.2rem;font-weight:800;letter-spacing:-1px;}\n.cover-logo span{color:var(--amber);}\n.cover-sub{font-size:.78rem;letter-spacing:.14em;text-transform:uppercase;color:rgba(255,255,255,0.45);margin-bottom:18px;}\n.cover-title{font-size:1.7rem;font-weight:300;margin-bottom:8px;line-height:1.2;}\n.cover-desc{color:rgba(255,255,255,0.65);max-width:480px;font-size:.92rem;}\n.cover-badge{display:inline-block;margin-top:22px;margin-right:8px;background:var(--amber);color:var(--navy);font-weight:700;font-size:.75rem;letter-spacing:.08em;padding:5px 14px;border-radius:20px;}\n.section-header{display:flex;align-items:center;gap:14px;margin:48px 0 24px;padding-bottom:12px;border-bottom:2px solid var(--navy);}\n.section-num{background:var(--navy);color:#fff;font-weight:800;font-size:.9rem;width:34px;height:34px;border-radius:50%;display:flex;align-items:center;justify-content:center;flex-shrink:0;}\n.section-title{font-size:1.25rem;font-weight:700;}\n.section-part{font-size:.7rem;letter-spacing:.14em;text-transform:uppercase;color:var(--amber);font-weight:700;margin-bottom:2px;}\n.sub-title{font-size:.98rem;font-weight:700;color:var(--navy);display:flex;align-items:center;gap:8px;margin:28px 0 12px;}\n.sub-title::before{content:\'\';display:inline-block;width:4px;height:16px;background:var(--amber);border-radius:2px;flex-shrink:0;}\n.intro-box{background:var(--navy);color:#fff;border-radius:12px;padding:22px 26px;margin:20px 0 28px;}\n.intro-box p{color:rgba(255,255,255,0.8);line-height:1.7;margin:0;}\n.steps{display:flex;flex-direction:column;gap:0;}\n.step{display:flex;gap:0;position:relative;}\n.step-left{display:flex;flex-direction:column;align-items:center;width:50px;flex-shrink:0;}\n.step-num{width:34px;height:34px;border-radius:50%;background:var(--navy);color:#fff;font-weight:800;font-size:.88rem;display:flex;align-items:center;justify-content:center;flex-shrink:0;z-index:1;}\n.step-line{width:2px;flex:1;min-height:20px;background:var(--border);margin-top:4px;}\n.step:last-child .step-line{display:none;}\n.step-body{background:var(--surface);border:1px solid var(--border);border-radius:12px;padding:16px 20px;margin-bottom:14px;flex:1;}\n.step-label{font-weight:700;font-size:.96rem;margin-bottom:5px;color:var(--navy);}\n.step-desc{color:var(--muted);font-size:.9rem;line-height:1.65;}\n.comp-map{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin:18px 0;}\n.comp-card{border-radius:10px;padding:14px 16px;border:1px solid var(--border);background:var(--surface2);}\n.comp-card-head{display:flex;align-items:center;gap:9px;margin-bottom:7px;}\n.comp-dot{width:9px;height:9px;border-radius:50%;flex-shrink:0;}\n.comp-name{font-weight:700;font-size:.86rem;}\n.comp-cats{display:flex;flex-wrap:wrap;gap:4px;margin-top:7px;}\n.cat-pill{font-size:.7rem;font-weight:700;padding:2px 8px;border-radius:12px;letter-spacing:.04em;}\n.comp-desc{font-size:.81rem;color:var(--muted);}\n.flow{display:flex;align-items:center;gap:0;margin:18px 0;overflow-x:auto;}\n.flow-node{background:var(--navy);color:#fff;border-radius:7px;padding:9px 14px;font-size:.8rem;font-weight:600;text-align:center;min-width:100px;flex-shrink:0;line-height:1.4;}\n.flow-node.teal{background:var(--teal);}\n.flow-node.amber{background:var(--amber);color:var(--navy);}\n.flow-arrow{font-size:1.1rem;color:var(--muted);padding:0 5px;flex-shrink:0;}\n.badge{display:inline-block;padding:2px 9px;border-radius:12px;font-size:.7rem;font-weight:700;letter-spacing:.05em;vertical-align:middle;}\n.badge-safe{background:#d4f5ee;color:#0a6b56;}\n.badge-warn{background:#fef3dc;color:#7a4e00;}\n.badge-flag{background:#fde8e8;color:#8b1a1a;}\n.badge-crit{background:#ede8fc;color:#3d1b8a;}\n.badge-pii{background:#fff3dc;color:#7a4e00;}\n.badge-clean{background:#d4f5ee;color:#0a6b56;}\n.pii-tag{display:inline-block;background:#fff3dc;color:#7a4e00;border:1px solid #e8c068;border-radius:4px;padding:0 6px;font-size:.7rem;font-weight:700;margin:0 2px;}\n.ann{display:inline-flex;align-items:center;justify-content:center;width:19px;height:19px;border-radius:50%;background:var(--amber);color:var(--navy);font-weight:800;font-size:.68rem;vertical-align:middle;margin-right:3px;flex-shrink:0;}\n.ann-list{list-style:none;margin:10px 0;padding:0;}\n.ann-list li{display:flex;align-items:flex-start;gap:9px;padding:7px 0;border-bottom:1px solid var(--border);font-size:.87rem;}\n.ann-list li:last-child{border-bottom:none;}\n.ann-text{flex:1;}\n.callout{border-radius:9px;padding:12px 16px;margin:14px 0;font-size:.87rem;display:flex;gap:10px;align-items:flex-start;}\n.callout-tip{background:#e8f4ff;border-left:4px solid var(--blue);}\n.callout-warn{background:#fff8e8;border-left:4px solid var(--amber);}\n.callout p{margin:0;color:var(--text);}\n.tox-table{width:100%;border-collapse:collapse;margin:12px 0;}\n.tox-table th{background:var(--navy);color:#fff;padding:7px 12px;text-align:left;font-size:.78rem;letter-spacing:.07em;text-transform:uppercase;}\n.tox-table td{padding:8px 12px;border-bottom:1px solid var(--border);font-size:.85rem;}\n.tox-table tr:last-child td{border-bottom:none;}\n.tox-table tr:nth-child(even) td{background:var(--surface2);}\n.ref-table{width:100%;border-collapse:collapse;margin:14px 0;}\n.ref-table th{background:var(--surface2);font-size:.76rem;text-transform:uppercase;letter-spacing:.07em;color:var(--muted);padding:7px 12px;text-align:left;border-bottom:2px solid var(--border);}\n.ref-table td{padding:8px 12px;border-bottom:1px solid var(--border);font-size:.85rem;}\n.ref-table tr:last-child td{border-bottom:none;}\n.hl-word{display:inline-block;border-radius:4px;padding:2px 7px;margin:2px;font-size:.86rem;direction:rtl;}\n.hl-high{background:rgba(192,57,43,0.82);color:#fff;font-weight:700;}\n.hl-mid{background:rgba(192,57,43,0.42);color:#5c1a15;font-weight:600;}\n.hl-low{background:rgba(192,57,43,0.17);color:#7a3020;}\n.hl-stop{background:rgba(160,160,160,0.1);color:#999;}\n.hl-purp-high{background:rgba(108,63,197,0.82);color:#fff;font-weight:700;}\n.hl-purp-mid{background:rgba(108,63,197,0.42);color:#2d1066;font-weight:600;}\n.hl-purp-low{background:rgba(108,63,197,0.17);color:#4a2090;}\n.rw-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-top:10px;}\n.rw-col-title{font-size:.7rem;letter-spacing:.1em;text-transform:uppercase;color:var(--muted);margin-bottom:7px;font-weight:600;}\n.rw-box{background:#fff;border:1px solid #ddd;border-radius:8px;padding:11px;font-size:.84rem;line-height:1.7;direction:rtl;text-align:right;min-height:72px;}\n.swatch{display:inline-block;width:11px;height:11px;border-radius:3px;vertical-align:middle;margin-right:5px;}\n.ext-popup{background:#f2ede2;border:1px solid #ddd;border-radius:14px;overflow:hidden;width:320px;margin:0 auto;box-shadow:0 8px 32px rgba(0,0,0,0.12);}\n.ext-header{background:#f2ede2;padding:14px 16px 10px;border-bottom:1px solid #ddd;display:flex;align-items:center;justify-content:space-between;}\n.ext-header-left{display:flex;align-items:center;gap:9px;}\n.ext-header-logo{font-weight:800;font-size:.95rem;color:#1a2340;}\n.ext-header-logo span{color:#e8941a;}\n.ext-header-sub{font-size:.65rem;color:#888;}\n.ext-icon-btn{width:28px;height:28px;background:#ebe5d8;border-radius:7px;display:flex;align-items:center;justify-content:center;font-size:.75rem;color:#555;cursor:pointer;flex-shrink:0;}\n.ext-section{padding:10px 14px 4px;}\n.ext-section-title{font-size:.65rem;letter-spacing:.12em;text-transform:uppercase;color:#888;margin-bottom:6px;font-weight:600;display:flex;align-items:center;gap:6px;}\n.ext-section-title::before{content:\'◆\';font-size:.5rem;color:#e8941a;}\n.ext-text-box{background:#fff;border:1px solid #ddd;border-radius:8px;padding:10px 12px;font-size:.82rem;line-height:1.7;direction:rtl;text-align:right;color:#333;min-height:52px;}\n.ext-tox-card{background:#fff;border-radius:9px;padding:11px 13px;border:1px solid #ddd;}\n.ext-tox-label{font-size:1rem;font-weight:800;color:var(--purple);}\n.ext-tox-conf{font-size:.73rem;color:#888;margin:2px 0 6px;}\n.ext-bar{background:#ede8e0;border-radius:4px;height:6px;}\n.ext-bar-fill{height:100%;border-radius:4px;background:var(--purple);width:52%;}\n.ext-badge{float:right;display:inline-block;padding:2px 9px;border-radius:12px;font-size:.68rem;font-weight:700;background:#ede8fc;color:#3d1b8a;margin-top:2px;}\n.ext-words{display:flex;flex-wrap:wrap;justify-content:flex-end;gap:5px;padding:6px 2px;direction:rtl;}\n.ext-btn{border-radius:8px;padding:10px;text-align:center;font-weight:700;font-size:.82rem;cursor:pointer;margin:3px 0;}\n.ext-btn-send{background:#e8941a;color:#fff;}\n.ext-btn-rewrite{background:#1a2340;color:#fff;}\n.ext-divider{height:1px;background:#ddd;margin:6px 14px;}\n.ext-setting-row{display:flex;align-items:center;justify-content:space-between;padding:11px 0;border-bottom:1px solid #ede8e0;}\n.ext-setting-row:last-child{border-bottom:none;}\n.ext-setting-label{font-weight:700;font-size:.84rem;color:#1a2340;}\n.ext-setting-desc{font-size:.72rem;color:#888;margin-top:1px;}\n.ext-toggle{width:40px;height:22px;border-radius:11px;position:relative;flex-shrink:0;}\n.ext-toggle-on{background:#e8941a;}\n.ext-toggle-off{background:#ccc;}\n.ext-toggle-knob{width:16px;height:16px;border-radius:50%;background:#fff;position:absolute;top:3px;}\n.ext-toggle-knob-on{left:21px;}\n.ext-toggle-knob-off{left:3px;}\n.ext-lang-btns{display:flex;gap:5px;}\n.ext-lang-btn{padding:4px 10px;border-radius:6px;font-size:.75rem;font-weight:600;}\n.ext-lang-active{background:#e8941a;color:#fff;}\n.ext-lang-inactive{background:#ebe5d8;color:#555;}\n.ext-settings-group-title{font-size:.65rem;letter-spacing:.14em;text-transform:uppercase;color:#888;font-weight:700;padding:10px 0 4px;display:flex;align-items:center;gap:5px;}\n.ext-settings-group-title::before{content:\'◆\';font-size:.45rem;color:#e8941a;}\n.ext-save-btn{background:#e8941a;color:#fff;border-radius:10px;padding:12px;text-align:center;font-weight:700;font-size:.88rem;margin-top:10px;cursor:pointer;}\n.doc-footer{background:var(--navy);color:rgba(255,255,255,0.5);text-align:center;padding:20px;font-size:.76rem;margin-top:48px;}\n.doc-footer span{color:var(--amber);}\n</style>\n<div class="guide-wrap">\n<div class="guide-tabs">\n  <div class="guide-tab active" onclick="switchTab(\'website\')" id="tab-website">Part 1 — Website</div>\n  <div class="guide-tab" onclick="switchTab(\'extension\')" id="tab-extension">Part 2 — Browser Extension</div>\n</div>\n\n<div class="tab-panel active" id="panel-website">\n<div class="cover"><div style="max-width:860px;margin:0 auto;padding:0 16px;">\n  <div class="cover-header">\n    <img src="data:image/png;base64," alt="logo"/>\n    <div><div class="cover-logo">Prompt<span>Scanner</span></div><div class="cover-sub">Arabic AI Safety Tool</div></div>\n  </div>\n  <div class="cover-title">User Guide — Part 1: Website</div>\n  <p class="cover-desc">Step-by-step instructions for using the PromptScanner web application to detect personal information and toxic content in Arabic prompts.</p>\n  <div class="cover-badge">Website Guide</div>\n</div></div>\n<div class="guide-page">\n<div class="section-header"><div class="section-num">1</div><div><div class="section-part">Getting started</div><div class="section-title">What is PromptScanner?</div></div></div>\n<div class="intro-box"><p>PromptScanner analyses your Arabic prompts <strong style="color:#fff;">before</strong> you send them to an AI chatbot. It simultaneously detects private personal information and checks for harmful content.</p></div>\n<div class="sub-title">How the analysis works</div>\n<div class="flow">\n  <div class="flow-node">Type a prompt</div><div class="flow-arrow">→</div>\n  <div class="flow-node amber">Press فحص</div><div class="flow-arrow">→</div>\n  <div class="flow-node teal">3 models run in parallel</div><div class="flow-arrow">→</div>\n  <div class="flow-node">Results appear</div>\n</div>\n<div class="comp-map">\n  <div class="comp-card"><div class="comp-card-head"><div class="comp-dot" style="background:#e8941a"></div><div class="comp-name">AraBERT NER</div></div><div class="comp-desc">Detects names, organisations, addresses and dates.</div><div class="comp-cats"><span class="cat-pill" style="background:#fff3dc;color:#7a4e00;">PERS</span><span class="cat-pill" style="background:#fff3dc;color:#7a4e00;">ORG</span><span class="cat-pill" style="background:#fff3dc;color:#7a4e00;">ADDRESS</span><span class="cat-pill" style="background:#fff3dc;color:#7a4e00;">DATETIME</span></div></div>\n  <div class="comp-card"><div class="comp-card-head"><div class="comp-dot" style="background:#0a8a72"></div><div class="comp-name">XLM-RoBERTa</div></div><div class="comp-desc">Detects IDs and credentials, including Latin values inside Arabic sentences.</div><div class="comp-cats"><span class="cat-pill" style="background:#d4f5ee;color:#0a4d3a;">ID</span><span class="cat-pill" style="background:#d4f5ee;color:#0a4d3a;">CREDENTIAL</span></div></div>\n  <div class="comp-card"><div class="comp-card-head"><div class="comp-dot" style="background:#1a5fa8"></div><div class="comp-name">Regex Engine</div></div><div class="comp-desc">Pattern-based detection for phone, email, IP, MAC, URL and financial info.</div><div class="comp-cats"><span class="cat-pill" style="background:#e8f0fc;color:#0e3a7a;">PHONE</span><span class="cat-pill" style="background:#e8f0fc;color:#0e3a7a;">EMAIL</span><span class="cat-pill" style="background:#e8f0fc;color:#0e3a7a;">IP</span><span class="cat-pill" style="background:#e8f0fc;color:#0e3a7a;">MAC</span><span class="cat-pill" style="background:#e8f0fc;color:#0e3a7a;">URL</span><span class="cat-pill" style="background:#e8f0fc;color:#0e3a7a;">FINANCIAL</span></div></div>\n  <div class="comp-card"><div class="comp-card-head"><div class="comp-dot" style="background:#6c3fc5"></div><div class="comp-name">AraBERT v2 — Toxicity</div></div><div class="comp-desc">Classifies prompts into 7 safety categories with keyword attention highlighting.</div><div class="comp-cats"><span class="cat-pill" style="background:#ede8fc;color:#3d1b8a;">7 categories</span><span class="cat-pill" style="background:#ede8fc;color:#3d1b8a;">Keyword attention</span></div></div>\n</div>\n\n<div class="section-header"><div class="section-num">2</div><div><div class="section-part">Interface overview</div><div class="section-title">Page layout</div></div></div>\n<ul class="ann-list">\n  <li><div class="ann">A</div><div class="ann-text"><strong>Model status panel (left sidebar)</strong> — shows which components are loaded (green dot = ready) and lists example prompts.</div></li>\n  <li><div class="ann">B</div><div class="ann-text"><strong>Prompt input box (centre)</strong> — type or paste Arabic text here. Right-to-left aligned.</div></li>\n  <li><div class="ann">C</div><div class="ann-text"><strong>فحص button</strong> — starts the scan. PII and toxicity run simultaneously.</div></li>\n  <li><div class="ann">D</div><div class="ann-text"><strong>مسح button</strong> — clears the input and resets results.</div></li>\n  <li><div class="ann">E</div><div class="ann-text"><strong>Top-right controls</strong> — toggle dark/light mode (🌙) and interface language (EN / AR).</div></li>\n</ul>\n\n<div class="section-header"><div class="section-num">3</div><div><div class="section-part">Step-by-step</div><div class="section-title">Scanning a prompt</div></div></div>\n<div class="steps">\n  <div class="step"><div class="step-left"><div class="step-num">1</div><div class="step-line"></div></div><div class="step-body"><div class="step-label">Enter your Arabic prompt</div><div class="step-desc">Click the text box and type or paste Arabic text. Click any sidebar example to auto-fill a test prompt.</div></div></div>\n  <div class="step"><div class="step-left"><div class="step-num">2</div><div class="step-line"></div></div><div class="step-body"><div class="step-label">Press فحص (Scan)</div><div class="step-desc">All four components analyse simultaneously. Results appear in 1–2 seconds. Press مسح to clear and restart.</div></div></div>\n  <div class="step"><div class="step-left"><div class="step-num">3</div><div class="step-line"></div></div><div class="step-body"><div class="step-label">Read the PII result (left card)</div><div class="step-desc">Shows <span class="badge badge-clean">CLEAN</span> or <span class="badge badge-pii">N found</span>. When PII is detected the masked text appears with <span class="pii-tag">[TYPE]</span> placeholders, and entity pills list each item with its value, type, and which model found it (RGX / NER / XLM).</div></div></div>\n  <div class="step"><div class="step-left"><div class="step-num">4</div><div class="step-line"></div></div><div class="step-body"><div class="step-label">Read the toxicity result (right card)</div><div class="step-desc">Shows the predicted category, confidence %, and a breakdown of all 7 categories.</div>\n    <table class="tox-table" style="margin-top:12px;"><thead><tr><th>Badge</th><th>Meaning</th><th>Categories</th></tr></thead><tbody>\n      <tr><td><span class="badge badge-safe">SAFE</span></td><td>No toxic content</td><td>Normal</td></tr>\n      <tr><td><span class="badge badge-warn">WARNING</span></td><td>Mildly harmful</td><td>Offensive · Privacy Violation · Mild Offense</td></tr>\n      <tr><td><span class="badge badge-flag">FLAGGED</span></td><td>Clearly harmful</td><td>Dangerous · Obscene</td></tr>\n      <tr><td><span class="badge badge-crit">CRITICAL</span></td><td>Requires care</td><td>Mental Health</td></tr>\n    </tbody></table>\n  </div></div>\n  <div class="step"><div class="step-left"><div class="step-num">5</div><div class="step-line"></div></div><div class="step-body"><div class="step-label">Read the keyword attention map</div><div class="step-desc">Words are colour-coded by how much they influenced the toxicity decision. Darker = more influential. Stop words appear grey.</div>\n    <div style="background:#fff;border:1px solid #ddd;border-radius:8px;padding:12px;margin-top:10px;text-align:right;direction:rtl;line-height:2.4;">\n      <span class="hl-stop">هذا</span><span class="hl-low">المعلم</span><span class="hl-stop">اللي</span><span class="hl-mid">خسف</span><span class="hl-mid">السلايدز</span><span class="hl-high">واريد</span><span class="hl-high">اصفعه</span><span class="hl-high">وافجره</span>\n    </div>\n    <div style="display:flex;gap:14px;flex-wrap:wrap;margin-top:10px;font-size:.77rem;color:#888;justify-content:flex-end;">\n      <span><span style="display:inline-block;width:11px;height:11px;background:rgba(192,57,43,0.82);border-radius:3px;vertical-align:middle;margin-right:3px;"></span>High (&gt;0.7)</span>\n      <span><span style="display:inline-block;width:11px;height:11px;background:rgba(192,57,43,0.42);border-radius:3px;vertical-align:middle;margin-right:3px;"></span>Medium</span>\n      <span><span style="display:inline-block;width:11px;height:11px;background:rgba(192,57,43,0.17);border-radius:3px;vertical-align:middle;margin-right:3px;"></span>Low</span>\n      <span><span style="display:inline-block;width:11px;height:11px;background:rgba(160,160,160,0.1);border-radius:3px;vertical-align:middle;margin-right:3px;"></span>Stop word</span>\n    </div>\n  </div></div>\n  <div class="step"><div class="step-left"><div class="step-num">6</div><div class="step-line" style="display:none;"></div></div><div class="step-body"><div class="step-label">Use إعادة الصياغة (Rewrite)</div><div class="step-desc">When toxic content is detected, the rewrite panel appears. It shows a safe alternative version of your prompt. Press the button to regenerate or copy the rewritten text to use instead of the original.</div>\n    <div class="rw-grid" style="margin-top:10px;">\n      <div><div class="rw-col-title">النص المُعاد كتابته</div><div class="rw-box">أريد تعليمات حول كيفية التعامل مع المعلمين الذين لا يوفرون تعليماً جيداً.</div></div>\n      <div><div class="rw-col-title">النص الأصلي</div><div class="rw-box" style="color:#999;">هذا المعلم اللي يدرسنا خسف وأريد اصفعه وافجره</div></div>\n    </div>\n  </div></div>\n</div>\n\n<div class="section-header"><div class="section-num">4</div><div><div class="section-part">Reference</div><div class="section-title">PII entity types</div></div></div>\n<table class="ref-table"><thead><tr><th>Tag</th><th>Entity</th><th>Example</th><th>Detected by</th></tr></thead><tbody>\n  <tr><td><span class="pii-tag">[PERS]</span></td><td>Person name</td><td>أحمد المقبالي</td><td>AraBERT NER</td></tr>\n  <tr><td><span class="pii-tag">[ORG]</span></td><td>Organisation</td><td>بنك مسقط</td><td>AraBERT NER</td></tr>\n  <tr><td><span class="pii-tag">[ADDRESS]</span></td><td>Location</td><td>مسقط، عُمان</td><td>AraBERT NER</td></tr>\n  <tr><td><span class="pii-tag">[DATETIME]</span></td><td>Date / time</td><td>الثلاثاء 5 مارس</td><td>AraBERT NER</td></tr>\n  <tr><td><span class="pii-tag">[ID]</span></td><td>National ID / passport</td><td>12345678</td><td>XLM-RoBERTa</td></tr>\n  <tr><td><span class="pii-tag">[CREDENTIAL]</span></td><td>Password / PIN / OTP</td><td>MyPass123!</td><td>XLM-RoBERTa</td></tr>\n  <tr><td><span class="pii-tag">[PHONE]</span></td><td>Phone number</td><td>+968 91234567</td><td>Regex</td></tr>\n  <tr><td><span class="pii-tag">[EMAIL]</span></td><td>Email address</td><td>ahmed@squ.edu.om</td><td>Regex</td></tr>\n  <tr><td><span class="pii-tag">[IP]</span></td><td>IP address</td><td>192.168.1.1</td><td>Regex</td></tr>\n  <tr><td><span class="pii-tag">[MAC]</span></td><td>MAC address</td><td>AA:BB:CC:DD:EE:FF</td><td>Regex</td></tr>\n  <tr><td><span class="pii-tag">[URL]</span></td><td>Web URL</td><td>https://example.com</td><td>Regex</td></tr>\n  <tr><td><span class="pii-tag">[FINANCIAL]</span></td><td>Card / IBAN</td><td>OM21BMI123…</td><td>Regex</td></tr>\n</tbody></table>\n\n<div class="section-header"><div class="section-num">5</div><div><div class="section-part">Reference</div><div class="section-title">Quick reference card</div></div></div>\n<table class="ref-table"><thead><tr><th>Action</th><th>How</th></tr></thead><tbody>\n  <tr><td>Scan a prompt</td><td>Type or paste text then press <strong>فحص</strong></td></tr>\n  <tr><td>Clear the input</td><td>Press <strong>مسح</strong></td></tr>\n  <tr><td>Try a pre-written example</td><td>Click any button in the left sidebar</td></tr>\n  <tr><td>Switch dark / light mode</td><td>Click 🌙 (top right)</td></tr>\n  <tr><td>Switch interface language</td><td>Click <strong>EN / AR</strong> (top right)</td></tr>\n  <tr><td>See which model found a PII entity</td><td>Check the small label on each entity pill (RGX / NER / XLM)</td></tr>\n  <tr><td>Get a safe rewrite</td><td>Press <strong>إعادة الصياغة</strong> in the rewrite panel</td></tr>\n  <tr><td>Understand toxic keywords</td><td>Read the keyword attention map (bottom panel)</td></tr>\n</tbody></table>\n\n</div>\n<div class="doc-footer"><span>PromptScanner</span> — User Guide · Part 1: Website</div>\n</div>\n\n<!-- ════ PART 2 ════ -->\n<div class="tab-panel" id="panel-extension">\n<div class="cover"><div style="max-width:860px;margin:0 auto;padding:0 16px;">\n  <div class="cover-header">\n    <img src="data:image/png;base64," alt="logo"/>\n    <div><div class="cover-logo">Prompt<span>Scanner</span></div><div class="cover-sub">Arabic AI Safety Tool</div></div>\n  </div>\n  <div class="cover-title">User Guide — Part 2: Browser Extension</div>\n  <p class="cover-desc">How to install and use the PromptScanner extension to scan prompts directly inside ChatGPT and Gemini before sending them.</p>\n  <div class="cover-badge">Extension Guide</div>\n  <div style="margin-top:12px;font-size:.8rem;color:rgba(255,255,255,0.5);">Compatible with ChatGPT &amp; Gemini</div>\n</div></div>\n\n<div class="guide-page">\n\n<div class="section-header"><div class="section-num">1</div><div><div class="section-part">Getting started</div><div class="section-title">What does the extension do?</div></div></div>\n<div class="intro-box"><p>The PromptScanner extension adds a safety layer directly inside <strong style="color:#fff;">ChatGPT</strong> and <strong style="color:#fff;">Gemini</strong>. When you press Send or Enter, it intercepts your prompt, scans it, and shows the results in a popup — before anything reaches the AI. You then choose to send the original, send a rewritten version, or cancel.</p></div>\n<div class="sub-title">Workflow</div>\n<div class="flow">\n  <div class="flow-node">Type in ChatGPT / Gemini</div><div class="flow-arrow">→</div>\n  <div class="flow-node amber">Press Send / Enter</div><div class="flow-arrow">→</div>\n  <div class="flow-node teal">Extension intercepts</div><div class="flow-arrow">→</div>\n  <div class="flow-node">You decide</div>\n</div>\n\n<div class="section-header"><div class="section-num">2</div><div><div class="section-part">Installation</div><div class="section-title">Installing the extension</div></div></div>\n<div class="steps">\n  <div class="step"><div class="step-left"><div class="step-num">1</div><div class="step-line"></div></div><div class="step-body"><div class="step-label">Open Chrome Extensions</div><div class="step-desc">Go to <strong>chrome://extensions</strong> in the address bar, or click the puzzle-piece icon and select <strong>Manage extensions</strong>.</div></div></div>\n  <div class="step"><div class="step-left"><div class="step-num">2</div><div class="step-line"></div></div><div class="step-body"><div class="step-label">Enable Developer Mode</div><div class="step-desc">Toggle <strong>Developer mode</strong> in the top-right corner of the extensions page.</div></div></div>\n  <div class="step"><div class="step-left"><div class="step-num">3</div><div class="step-line"></div></div><div class="step-body"><div class="step-label">Load the extension folder</div><div class="step-desc">Click <strong>Load unpacked</strong> and select the PromptScanner extension folder. The icon appears in the Chrome toolbar.</div></div></div>\n  <div class="step"><div class="step-left"><div class="step-num">4</div><div class="step-line" style="display:none;"></div></div><div class="step-body"><div class="step-label">Pin the extension</div><div class="step-desc">Click the puzzle-piece icon, find PromptScanner, and click the pin so it stays visible in the toolbar.</div></div></div>\n</div>\n\n<div class="section-header"><div class="section-num">3</div><div><div class="section-part">Using the extension</div><div class="section-title">Popup states</div></div></div>\n<p style="color:var(--muted);font-size:.9rem;margin-bottom:20px;">When you press Send inside ChatGPT or Gemini, the popup appears showing the scan result. There are three states depending on what was found.</p>\n\n<div class="sub-title">State A — Safe content (no issues found)</div>\n<div style="display:grid;grid-template-columns:320px 1fr;gap:24px;align-items:start;margin:16px 0 28px;">\n  <div class="ext-popup">\n    <div class="ext-header"><div class="ext-header-left"><img src="data:image/png;base64," style="width:24px;height:24px;border-radius:5px;" alt="logo"/><div><div class="ext-header-logo">Prompt<span>Scanner</span></div><div class="ext-header-sub">Privacy &amp; Safety Scanner</div></div></div><div class="ext-icon-btn">⚙</div></div>\n    <div style="text-align:center;padding:6px 14px 2px;font-size:.7rem;color:#888;">Scanned in 0.15s</div>\n    <div class="ext-section"><div class="ext-section-title">Masked text</div><div class="ext-text-box" style="color:#aaa;text-align:center;padding-top:14px;">النص بدون معلومات خاصة ✓</div></div>\n    <div class="ext-section"><div class="ext-section-title">Toxicity analysis</div><div class="ext-tox-card" style="border-left:3px solid #0a8a72;"><div class="ext-tox-label" style="color:#0a8a72;">Normal</div><div class="ext-tox-conf">Confidence: 98.2%</div><div class="ext-bar"><div class="ext-bar-fill" style="background:#0a8a72;width:98%;"></div></div></div></div>\n    <div class="ext-divider"></div>\n    <div style="padding:8px 14px 14px;"><div class="ext-btn ext-btn-send">→ إرسال الأصلي</div></div>\n  </div>\n  <ul class="ann-list">\n    <li><div class="ann">1</div><div class="ann-text"><strong>Masked text</strong> confirms no PII was found.</div></li>\n    <li><div class="ann">2</div><div class="ann-text"><strong>Green Normal label</strong> — content is safe.</div></li>\n    <li><div class="ann">3</div><div class="ann-text"><strong>→ إرسال الأصلي</strong> — sends the prompt as-is. One click and done.</div></li>\n  </ul>\n</div>\n\n<div class="sub-title">State B — Issues detected (initial view)</div>\n<div style="display:grid;grid-template-columns:320px 1fr;gap:24px;align-items:start;margin:16px 0 28px;">\n  <div class="ext-popup">\n    <div class="ext-header"><div class="ext-header-left"><img src="data:image/png;base64," style="width:24px;height:24px;border-radius:5px;" alt="logo"/><div><div class="ext-header-logo">Prompt<span>Scanner</span></div><div class="ext-header-sub">Privacy &amp; Safety Scanner</div></div></div><div class="ext-icon-btn">⚙</div></div>\n    <div style="text-align:center;padding:6px 14px 2px;font-size:.7rem;color:#888;">Scanned in 0.15s</div>\n    <div class="ext-section"><div class="ext-section-title">Masked text</div><div class="ext-text-box">اسمي سارة واحس الحياة غير عادلة</div></div>\n    <div class="ext-section"><div class="ext-section-title">Toxicity analysis</div><div class="ext-tox-card" style="border-left:3px solid #6c3fc5;"><div class="ext-badge">Critical</div><div class="ext-tox-label">Mental Health</div><div class="ext-tox-conf">Confidence: 51.9%</div><div class="ext-bar"><div class="ext-bar-fill" style="width:52%;"></div></div></div></div>\n    <div class="ext-section"><div class="ext-section-title">Key attention words</div><div class="ext-words"><span class="hl-purp-high" style="font-size:.8rem;">اسمي</span><span class="hl-purp-mid" style="font-size:.8rem;">سارة</span><span class="hl-purp-mid" style="font-size:.8rem;">واحس</span><span class="hl-purp-low" style="font-size:.8rem;">الحياة</span><span class="hl-stop" style="font-size:.8rem;">غير</span><span class="hl-purp-low" style="font-size:.8rem;">عادلة</span></div></div>\n    <div class="ext-divider"></div>\n    <div style="padding:8px 14px 14px;display:flex;flex-direction:column;gap:6px;">\n      <div class="ext-btn" style="background:#1a2340;color:#fff;">إعادة الصياغة</div>\n      <div class="ext-btn ext-btn-send">→ إرسال الأصلي</div>\n    </div>\n  </div>\n  <ul class="ann-list">\n    <li><div class="ann">1</div><div class="ann-text"><strong>Masked text</strong> — prompt shown; PII would appear as [TYPE] tags if detected.</div></li>\n    <li><div class="ann">2</div><div class="ann-text"><strong>Purple Critical badge</strong> — Mental Health classification detected.</div></li>\n    <li><div class="ann">3</div><div class="ann-text"><strong>Key attention words</strong> — purple highlights show which words drove the classification.</div></li>\n    <li><div class="ann">4</div><div class="ann-text"><strong>إعادة الصياغة</strong> — press to generate a safe rewrite (moves to State C).</div></li>\n    <li><div class="ann">5</div><div class="ann-text"><strong>→ إرسال الأصلي</strong> — always available; the choice is yours.</div></li>\n  </ul>\n</div>\n\n<div class="sub-title">State C — Rewrite generated</div>\n<div style="display:grid;grid-template-columns:320px 1fr;gap:24px;align-items:start;margin:16px 0 28px;">\n  <div class="ext-popup">\n    <div class="ext-header"><div class="ext-header-left"><img src="data:image/png;base64," style="width:24px;height:24px;border-radius:5px;" alt="logo"/><div><div class="ext-header-logo">Prompt<span>Scanner</span></div><div class="ext-header-sub">Privacy &amp; Safety Scanner</div></div></div><div class="ext-icon-btn">⚙</div></div>\n    <div style="text-align:center;padding:6px 14px 2px;font-size:.7rem;color:#888;">Scanned in 0.15s</div>\n    <div class="ext-section"><div class="ext-section-title">Masked text</div><div class="ext-text-box">اسمي سارة واحس الحياة غير عادلة</div></div>\n    <div class="ext-section"><div class="ext-section-title">Toxicity analysis</div><div class="ext-tox-card" style="border-left:3px solid #6c3fc5;"><div class="ext-badge">Critical</div><div class="ext-tox-label">Mental Health</div><div class="ext-tox-conf">Confidence: 51.9%</div><div class="ext-bar"><div class="ext-bar-fill" style="width:52%;"></div></div></div></div>\n    <div class="ext-section"><div class="ext-section-title">Key attention words</div><div class="ext-words"><span class="hl-purp-high" style="font-size:.8rem;">اسمي</span><span class="hl-purp-mid" style="font-size:.8rem;">سارة</span><span class="hl-purp-mid" style="font-size:.8rem;">واحس</span><span class="hl-purp-low" style="font-size:.8rem;">الحياة</span><span class="hl-purp-low" style="font-size:.8rem;">عادلة</span></div></div>\n    <div class="ext-section" style="padding-bottom:8px;"><div class="ext-section-title" style="color:#0a8a72;">النص المُعاد كتابته</div><div class="ext-text-box" style="border-color:#0a8a72;border-width:1.5px;font-size:.8rem;">أنا سارة وأشعر بالحاجة إلى فهم سبب عدم توازن الحياة في حياتي.</div></div>\n    <div class="ext-divider"></div>\n    <div style="padding:8px 14px 14px;display:grid;grid-template-columns:1fr 1fr;gap:6px;">\n      <div class="ext-btn" style="background:#0a8a72;color:#fff;font-size:.75rem;">→ إرسال المُعاد كتابته</div>\n      <div class="ext-btn ext-btn-send" style="font-size:.75rem;">→ إرسال الأصلي</div>\n    </div>\n    <div style="padding:0 14px 12px;"><div class="ext-btn" style="background:#ebe5d8;color:#555;text-align:center;font-size:.78rem;">✕ إلغاء</div></div>\n  </div>\n  <ul class="ann-list">\n    <li><div class="ann">1</div><div class="ann-text"><strong>النص المُعاد كتابته</strong> — the safe alternative appears with a green border.</div></li>\n    <li><div class="ann">2</div><div class="ann-text"><strong>→ إرسال المُعاد كتابته</strong> — sends the rewritten, safe version.</div></li>\n    <li><div class="ann">3</div><div class="ann-text"><strong>→ إرسال الأصلي</strong> — sends your original despite the warning.</div></li>\n    <li><div class="ann">4</div><div class="ann-text"><strong>✕ إلغاء</strong> — closes the popup without sending so you can edit manually.</div></li>\n  </ul>\n</div>\n\n<div class="section-header"><div class="section-num">4</div><div><div class="section-part">Configuration</div><div class="section-title">Extension settings</div></div></div>\n<p style="color:var(--muted);font-size:.9rem;margin-bottom:18px;">Click the ⚙ icon in the popup header to open settings.</p>\n<div style="display:grid;grid-template-columns:320px 1fr;gap:24px;align-items:start;">\n  <div class="ext-popup">\n    <div class="ext-header"><div class="ext-header-left"><img src="data:image/png;base64," style="width:24px;height:24px;border-radius:5px;" alt="logo"/><div><div class="ext-header-logo">Prompt<span>Scanner</span></div><div class="ext-header-sub">Privacy &amp; Safety Scanner</div></div></div><div class="ext-icon-btn" style="background:#e74c3c;color:#fff;">✕</div></div>\n    <div style="padding:10px 16px 4px;">\n      <div class="ext-settings-group-title">Appearance</div>\n      <div style="background:#fff;border-radius:10px;padding:10px 14px;border:1px solid #ddd;">\n        <div class="ext-setting-row"><div><div class="ext-setting-label">Dark Mode</div><div class="ext-setting-desc">Enable dark theme</div></div><div class="ext-toggle ext-toggle-off"><div class="ext-toggle-knob ext-toggle-knob-off"></div></div></div>\n        <div class="ext-setting-row"><div><div class="ext-setting-label">Language</div><div class="ext-setting-desc">Extension UI language</div></div><div class="ext-lang-btns"><div class="ext-lang-btn ext-lang-inactive">العربية</div><div class="ext-lang-btn ext-lang-active">English</div></div></div>\n      </div>\n      <div class="ext-settings-group-title" style="margin-top:10px;">Behavior</div>\n      <div style="background:#fff;border-radius:10px;padding:10px 14px;border:1px solid #ddd;">\n        <div class="ext-setting-row"><div><div class="ext-setting-label">Show popup for safe content</div><div class="ext-setting-desc">If safe, show popup. Otherwise send automatically</div></div><div class="ext-toggle ext-toggle-on"><div class="ext-toggle-knob ext-toggle-knob-on"></div></div></div>\n        <div class="ext-setting-row"><div><div class="ext-setting-label">Auto Scan</div><div class="ext-setting-desc">Scan when Send or Enter is pressed</div></div><div class="ext-toggle ext-toggle-on"><div class="ext-toggle-knob ext-toggle-knob-on"></div></div></div>\n      </div>\n      <div class="ext-save-btn">✓ Save Settings</div>\n    </div>\n  </div>\n  <table class="ref-table">\n    <thead><tr><th>Setting</th><th>What it does</th></tr></thead>\n    <tbody>\n      <tr><td><strong>Dark Mode</strong></td><td>Switches popup to a dark colour scheme.</td></tr>\n      <tr><td><strong>Language</strong></td><td>Choose English or Arabic for all popup labels.</td></tr>\n      <tr><td><strong>Show popup for safe content</strong></td><td><strong>ON</strong>: popup appears even for safe prompts. <strong>OFF</strong>: safe prompts sent automatically with no interruption.</td></tr>\n      <tr><td><strong>Auto Scan</strong></td><td><strong>ON</strong>: scans automatically when Send/Enter is pressed. <strong>OFF</strong>: no automatic scanning.</td></tr>\n    </tbody>\n  </table>\n</div>\n<div class="callout callout-warn" style="margin-top:14px;"><div style="font-size:1rem;line-height:1.6;flex-shrink:0;">⚠</div><p>Always press <strong>Save Settings</strong> after making changes. Changes are not applied until saved.</p></div>\n\n<div class="section-header"><div class="section-num">5</div><div><div class="section-part">Reference</div><div class="section-title">Extension quick reference</div></div></div>\n<table class="ref-table"><thead><tr><th>Action</th><th>How</th></tr></thead><tbody>\n  <tr><td>Trigger a scan</td><td>Press Send or Enter in ChatGPT / Gemini (requires Auto Scan ON)</td></tr>\n  <tr><td>Send original prompt</td><td>Press <strong>→ إرسال الأصلي</strong></td></tr>\n  <tr><td>Send rewritten version</td><td>Press <strong>إعادة الصياغة</strong> then <strong>→ إرسال المُعاد كتابته</strong></td></tr>\n  <tr><td>Cancel without sending</td><td>Press <strong>✕ إلغاء</strong></td></tr>\n  <tr><td>Open settings</td><td>Click ⚙ in the popup header</td></tr>\n  <tr><td>Skip popup for safe prompts</td><td>Turn OFF "Show popup for safe content"</td></tr>\n  <tr><td>Disable auto-scanning</td><td>Turn OFF "Auto Scan"</td></tr>\n</tbody></table>\n\n</div>\n<div class="doc-footer"><span>PromptScanner</span> — User Guide · Part 2: Browser Extension · ChatGPT &amp; Gemini</div>\n</div>\n\n</div>\n\n<script>\nfunction switchTab(tab) {\n  document.querySelectorAll(\'.tab-panel\').forEach(function(p){ p.classList.remove(\'active\'); });\n  document.querySelectorAll(\'.guide-tab\').forEach(function(t){ t.classList.remove(\'active\'); });\n  document.getElementById(\'panel-\' + tab).classList.add(\'active\');\n  document.getElementById(\'tab-\' + tab).classList.add(\'active\');\n  window.scrollTo(0, 0);\n}\n</script>\n'
